static bool simplifySwitchOfCmpIntrinsic(SwitchInst *SI,
                                         IRBuilder<> &Builder) {
  auto *CI = dyn_cast<CmpIntrinsic>(SI->getCondition());
  if (!CI)
    return false;

  // The [us]cmp intrinsic returns only -1, 0, or 1.
  // Map each possible value to its destination block (default if not covered
  // by an explicit case).
  BasicBlock *DestForMinusOne = SI->getDefaultDest();
  BasicBlock *DestForZero = SI->getDefaultDest();
  BasicBlock *DestForOne = SI->getDefaultDest();

  for (const auto &Case : SI->cases()) {
    const APInt &Val = Case.getCaseValue()->getValue();
    if (Val.isAllOnes())
      DestForMinusOne = Case.getCaseSuccessor();
    else if (Val.isZero())
      DestForZero = Case.getCaseSuccessor();
    else if (Val.isOne())
      DestForOne = Case.getCaseSuccessor();
    else
      return false; // Unexpected value for [us]cmp result.
