  if (DestForMinusOne == DestForZero && DestForZero == DestForOne) {
    Builder.SetInsertPoint(SI);
    Builder.CreateBr(DestForMinusOne);
    SI->eraseFromParent();
    return true;
  }

  // Determine the destination that receives the "odd one out" value (i.e.,
  // the value that goes to a different destination than the other two).
  BasicBlock *SingleDest = nullptr;
  BasicBlock *PairDest = nullptr;
  ICmpInst::Predicate SinglePred, PairPred;

  if (DestForMinusOne != DestForZero && DestForMinusOne == DestForOne) {
    // 0 is the single value, -1 and 1 go to the same dest.
    SingleDest = DestForZero;
    PairDest = DestForMinusOne;
    SinglePred = ICmpInst::ICMP_EQ;
    PairPred = ICmpInst::ICMP_NE;
  } else if (DestForZero != DestForMinusOne && DestForZero == DestForOne) {
    // -1 is the single value, 0 and 1 go to the same dest.
    SingleDest = DestForMinusOne;
    PairDest = DestForZero;
    SinglePred = CI->getLTPredicate();
    PairPred = CI->getGTPredicate();
