///
/// This transformation allows better lowering and could allow transforming into
/// a lookup table.
static bool simplifySwitchOfCmpIntrinsic(SwitchInst *SI,
                                         IRBuilder<> &Builder) {
  auto *CI = dyn_cast<CmpIntrinsic>(SI->getCondition());
  if (!CI)
    return false;

  // The [us]cmp intrinsic returns only -1, 0, or 1.
  // Map each possible value to its destination block (default if not covered
  // by an explicit case).
  BasicBlock *DestForMinusOne = SI->getDefaultDest();
  BasicBlock *DestForZero = SI->getDefaultDest();
  BasicBlock *DestForOne = SI->getDefaultDest();

  for (const auto &Case : SI->cases()) {
    const APInt &Val = Case.getCaseValue()->getValue();
    if (Val.isAllOnes())
      DestForMinusOne = Case.getCaseSuccessor();
    else if (Val.isZero())
      DestForZero = Case.getCaseSuccessor();
    else if (Val.isOne())
      DestForOne = Case.getCaseSuccessor();
    else
      return false; // Unexpected value for [us]cmp result.
  }

  BasicBlock *BB = SI->getParent();

  // If all three go to the same destination, branch unconditionally.
  if (DestForMinusOne == DestForZero && DestForZero == DestForOne) {
    Builder.SetInsertPoint(SI);
    Builder.CreateBr(DestForMinusOne);
    // Remove PHI entries for all successors other than DestForMinusOne.
    for (unsigned I = 0, E = SI->getNumSuccessors(); I != E; ++I) {
      BasicBlock *Succ = SI->getSuccessor(I);
      if (Succ != DestForMinusOne)
        Succ->removePredecessor(BB);
    }
    SI->eraseFromParent();
    return true;
  }

  // Determine which value is the "odd one out" (goes to a different
  // destination than the other two).
  BasicBlock *SingleDest = nullptr;
  BasicBlock *PairDest = nullptr;
  ICmpInst::Predicate Pred;

  if (DestForMinusOne != DestForZero && DestForMinusOne == DestForOne) {
    // 0 is the single value, -1 and 1 go to the same dest.
    SingleDest = DestForZero;
    PairDest = DestForMinusOne;
    Pred = ICmpInst::ICMP_EQ;
  } else if (DestForZero != DestForMinusOne && DestForZero == DestForOne) {
    // -1 is the single value, 0 and 1 go to the same dest.
    SingleDest = DestForMinusOne;
    PairDest = DestForZero;
    Pred = CI->getLTPredicate();
  } else if (DestForOne != DestForMinusOne && DestForOne == DestForZero) {
    // 1 is the single value, -1 and 0 go to the same dest.
    SingleDest = DestForOne;
    PairDest = DestForMinusOne;
    Pred = CI->getGTPredicate();
  } else {
    // More than two distinct destinations, can't simplify.
    return false;
  }

  // Count how many switch edges go to each successor.
  SmallDenseMap<BasicBlock *, unsigned> EdgeCount;
  for (const auto &Case : SI->cases())
    ++EdgeCount[Case.getCaseSuccessor()];
  ++EdgeCount[SI->getDefaultDest()];

  // Create the icmp and conditional branch.
  Builder.SetInsertPoint(SI);
  Value *Cmp = Builder.CreateICmp(Pred, CI->getLHS(), CI->getRHS());
  Builder.CreateCondBr(Cmp, SingleDest, PairDest);

  // Deduplicate PHI entries for SingleDest and PairDest (the switch may have
  // had multiple edges to them).
  for (BasicBlock *Succ : {SingleDest, PairDest}) {
    unsigned Cnt = EdgeCount[Succ];
    if (Cnt > 1) {
      for (auto BBI = Succ->begin(); isa<PHINode>(BBI); ++BBI)
        for (unsigned I = 0, E = Cnt - 1; I != E; ++I)
          cast<PHINode>(BBI)->removeIncomingValue(BB);
    }
  }

  // Remove PHI entries for successors that are no longer reachable.
  for (unsigned I = 0, E = SI->getNumSuccessors(); I != E; ++I) {
    BasicBlock *Succ = SI->getSuccessor(I);
    if (Succ != SingleDest && Succ != PairDest)
      Succ->removePredecessor(BB);
  }

  // Remove the switch.
  SI->eraseFromParent();
  return true;
}

