  7915 | 
  7916 |   // Check for and eliminate duplicate PHI nodes in this block.
  7917 |   Changed |= EliminateDuplicatePHINodes(BB);
  7918 | 
  7919 |   // Check for and remove branches that will always cause undefined behavior.
  7920 |   if (removeUndefIntroducingPredecessor(BB, DTU, Options.AC))
  7921 |     return requestResimplify();
  7922 | 
  7923 |   // Merge basic blocks into their predecessor if there is only one distinct
  7924 |   // pred, and if there is only one distinct successor of the predecessor, and
  7925 |   // if there are no PHI nodes.
  7926 |   if (MergeBlockIntoPredecessor(BB, DTU))
  7927 |     return true;
  7928 | 
  7929 |   if (SinkCommon && Options.SinkCommonInsts)
