  7931 |         mergeCompatibleInvokes(BB, DTU)) {
  7932 |       // sinkCommonCodeFromPredecessors() does not automatically CSE PHI's,
  7933 |       // so we may now how duplicate PHI's.
  7934 |       // Let's rerun EliminateDuplicatePHINodes() first,
  7935 |       // before foldTwoEntryPHINode() potentially converts them into select's,
  7936 |       // after which we'd need a whole EarlyCSE pass run to cleanup them.
  7937 |       return true;
  7938 |     }
  7939 | 
  7940 |   IRBuilder<> Builder(BB);
  7941 | 
  7942 |   if (Options.SpeculateBlocks &&
  7943 |       !BB->getParent()->hasFnAttribute(Attribute::OptForFuzzing)) {
  7944 |     // If there is a trivial two-entry PHI node in this basic block, and we can
  7945 |     // eliminate it, do so now.
