  7956 |   case Instruction::Br:
  7957 |     Changed |= simplifyBranch(cast<BranchInst>(Terminator), Builder);
  7958 |     break;
  7959 |   case Instruction::Resume:
  7960 |     Changed |= simplifyResume(cast<ResumeInst>(Terminator), Builder);
  7961 |     break;
  7962 |   case Instruction::CleanupRet:
  7963 |     Changed |= simplifyCleanupReturn(cast<CleanupReturnInst>(Terminator));
  7964 |     break;
  7965 |   case Instruction::Switch:
  7966 |     Changed |= simplifySwitch(cast<SwitchInst>(Terminator), Builder);
  7967 |     break;
  7968 |   case Instruction::Unreachable:
  7969 |     Changed |= simplifyUnreachable(cast<UnreachableInst>(Terminator));
